<?php declare(strict_types=1);
namespace App\Services;
use App\Repositories\{ChannelRepository,StreamRepository};
final class ChannelService { public function __construct(private ChannelRepository $channels,private StreamRepository $streams,private LogService $log){} public function all():array{return $this->channels->all();} public function create(array $d):void{$this->save(null,$d);} public function update(int $id,array $d):void{$this->save($id,$d);} public function duplicate(int $id):void{$c=$this->find($id);if(!$c)throw new \InvalidArgumentException('Channel not found.');$c['name'].=' (Copy)';$c['is_default']=false;$this->create($c);} public function toggle(int $id):void{$c=$this->find($id);if(!$c)throw new \InvalidArgumentException('Channel not found.');$c['enabled']=!$c['enabled'];$this->update($id,$c);} public function delete(int $id):void{if(($this->streams->active()['channel_id']??0)===$id)throw new \LogicException('Cannot delete the active streaming channel.');$this->channels->delete($id);$this->log->info('Channel deleted',['id'=>$id]);} public function find(int $id):?array{return $this->channels->find($id);} private function save(?int $id,array $d):void{$existing=$id?$this->find($id):null;if($id&&!$existing)throw new \InvalidArgumentException('Channel not found.');if(trim((string)($d['stream_key']??''))==='')$d['stream_key']=$existing['stream_key']??'';$this->validate($d);$clean=['name'=>trim($d['name']),'description'=>trim($d['description']??''),'rtmp_url'=>trim($d['rtmp_url']),'stream_key'=>trim($d['stream_key']),'enabled'=>isset($d['enabled'])?(int)(bool)$d['enabled']:1,'is_default'=>isset($d['is_default'])?(int)(bool)$d['is_default']:0];if($clean['is_default'])$this->channels->clearDefaults();$id?$this->channels->update($id,$clean):$this->channels->create($clean);$this->log->info($id?'Channel updated':'Channel created',['id'=>$id,'name'=>$clean['name']]);} private function validate(array $d):void{foreach(['name','rtmp_url','stream_key']as$key)if(trim((string)($d[$key]??''))==='')throw new \InvalidArgumentException('All required channel fields must be supplied.');if(!filter_var($d['rtmp_url'],FILTER_VALIDATE_URL))throw new \InvalidArgumentException('RTMP URL must be a valid URL.');} }
